vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
float ang2, c, s;
vUv -= 0.5;
vUv *= uAspect.xy;

vec2 tmp = vUv;
float dist = 1;
float inten = 1;
ret1 = 0;
int anz = 4;
float n = 1;
while (n <= anz) {
    c = n%2-.5;
    s = (n+1)%2-.5;
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
    uv2 *= uAspect.yx;
    dist = 1-fract(.25*n+q31);
    inten =  2*sqrt(dist)*(1-dist*dist);

    neu = texture(sampler_main, 2*uv2*dist + q32);
    ret1 = max(ret1,neu*inten);
n++;
}

ret = ret1*1.6;// * lum(ret1) ;


  fragColor = ret;
}
